LOGIN_HTML = LOGIN_HTML.replace("AVATAR_PLACEHOLDER", AVATAR_B64)

# ── render_login_page ─────────────────────────────────────────────────────────

def render_login_page():
    # Initialiseer session state
    if "authenticated" not in st.session_state:
        st.session_state.authenticated = False
    if "username" not in st.session_state:
        st.session_state.username = None
    if "role" not in st.session_state:
        st.session_state.role = "user"
    if "show_register" not in st.session_state:
        st.session_state.show_register = False

    if st.session_state.authenticated:
        return

    # Verberg Streamlit chrome
    st.markdown("""
        <style>
        header {visibility: hidden;}
        [data-testid="stToolbar"] {display: none;}
        .main > div:first-child {padding-top: 0;}
        </style>
    """, unsafe_allow_html=True)

    # ── Registreren ──
    if st.session_state.show_register:
        st.markdown("## 📝 Registreren")
        new_username = st.text_input("Gebruikersnaam", key="reg_username")
        new_email    = st.text_input("E-mail (optioneel)", key="reg_email")
        new_password = st.text_input("Wachtwoord", type="password", key="reg_password")
        new_password2 = st.text_input("Bevestig wachtwoord", type="password", key="reg_password2")

        col1, col2 = st.columns(2)
        with col1:
            if st.button("Account aanmaken", type="primary", use_container_width=True):
                if new_password != new_password2:
                    st.error("Wachtwoorden komen niet overeen")
                elif not new_username or not new_password:
                    st.error("Vul alle verplichte velden in")
                else:
                    success, message = register_user(new_username, new_password, new_email)
                    if success:
                        st.success(message + " – Je kan nu inloggen!")
                        st.session_state.show_register = False
                        st.rerun()
                    else:
                        st.error(message)
        with col2:
            if st.button("← Terug naar login", use_container_width=True):
                st.session_state.show_register = False
                st.rerun()
        return

    # ── HTML loginpagina ──
    components.html(LOGIN_HTML, height=650, scrolling=False)

    # ── Native fallback form (Streamlit kan geen JS postMessage ontvangen) ──
    st.markdown("---")
    st.markdown("#### 🔐 Inloggen")
    username = st.text_input("Gebruikersnaam", key="login_username")
    password = st.text_input("Wachtwoord", type="password", key="login_password")

    col1, col2 = st.columns(2)
    with col1:
        if st.button("Inloggen", type="primary", use_container_width=True):
            if verify_user(username, password):
                users = load_users()
                st.session_state.authenticated = True
                st.session_state.username = username
                st.session_state.role = users[username].get("role", "user")
                st.rerun()
            else:
                st.error("Ongeldige gebruikersnaam of wachtwoord")
    with col2:
        if st.button("Registreren", use_container_width=True):
            st.session_state.show_register = True
            st.rerun()


# ── render_admin_panel ────────────────────────────────────────────────────────

def render_admin_panel():
    st.markdown("## ⚙️ Admin Panel")
    users = load_users()

    st.markdown(f"**Totaal aantal gebruikers:** {len(users)}")
    st.markdown("---")

    for username, data in users.items():
        with st.expander(f"👤 {username}"):
            st.write(f"**E-mail:** {data.get('email', 'N/A')}")
            st.write(f"**Rol:** {data.get('role', 'user')}")
            st.write(f"**Aangemaakt:** {data.get('created_at', 'N/A')}")

            col1, col2 = st.columns(2)
            with col1:
                if data.get("role") != "admin":
                    if st.button("Maak admin", key=f"admin_{username}"):
                        users[username]["role"] = "admin"
                        save_users(users)
                        st.success(f"{username} is nu admin")
                        st.rerun()
            with col2:
                if username != st.session_state.get("username"):
                    if st.button("Verwijder", key=f"del_{username}"):
                        del users[username]
                        save_users(users)
                        st.success(f"{username} verwijderd")
                        st.rerun()
